import time
def timer(func):
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print(f'{func.__name__} took {end - start:.4f}s')
        return result
    return wrapper

def divide(a, b):
    try:
        result = a / b
    except ZeroDivisionError:
        return 'Cannot divide by zero!'
    except TypeError:
        return 'Invalid types!'
    else:
        return result
    finally:
        print('Operation attempted.')

print(divide(10, 0))
